Step.Calculation:
JSONSetElement ( "{}" ;
	[ "test"     ; "Create kalkulacija"                                                                         ; JSONString ] ;
	[ "severity" ; Case ( JSONGetElement ( $result ; "status" ) = "success" and not IsEmpty ( JSONGetElement ( $result ; "data.kalkulacijaID" ) ) ; "pass" ; "error" ) ; JSONString ] ;
	[ "result"   ; $result                                                                                      ; JSONObject ]
)

JSONSetElement ( "{}" ;
	[ "test"     ; "Create duplicate (idempotent)"                                                                                                                        ; JSONString ] ;
	[ "severity" ; Case ( JSONGetElement ( $result ; "status" ) = "success" and JSONGetElement ( $result ; "data.kalkulacijaID" ) = $kalkulacijaID ; "pass" ; "error" )   ; JSONString ] ;
	[ "result"   ; $result                                                                                                                                                ; JSONObject ] ;
	[ "note"     ; "Expected: success + same kalkulacijaID. Script is idempotent — must not create a duplicate."                                                         ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "test"     ; "Generate stavke"                                                                                                          ; JSONString ] ;
	[ "severity" ; Case ( JSONGetElement ( $result ; "status" ) = "success" and $stavkeCount > 0 ; "pass" ; "error" )                        ; JSONString ] ;
	[ "result"   ; $result                                                                                                                    ; JSONObject ]
)

JSONSetElement ( "{}" ;
	[ "test"     ; "Generate again (guard: ALREADY_GENERATED)"                                    ; JSONString ] ;
	[ "severity" ; Case ( JSONGetElement ( $result ; "status" ) = "fail" ; "pass" ; "error" )    ; JSONString ] ;
	[ "result"   ; $result                                                                         ; JSONObject ] ;
	[ "note"     ; "Expected: fail — stavke already exist for this kalkulacija."                  ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "test"     ; "Post kalkulacija"                                                                                                                              ; JSONString ] ;
	[ "severity" ; Case ( JSONGetElement ( $result ; "status" ) = "success" and GetAsNumber ( JSONGetElement ( $result ; "data.ukupnoMP_Roba" ) ) > 0 ; "pass" ; "error" ) ; JSONString ] ;
	[ "result"   ; $result                                                                                                                                         ; JSONObject ]
)

JSONSetElement ( "{}" ;
	[ "test"     ; "Post again (guard: INVALID_STATUS)"                                         ; JSONString ] ;
	[ "severity" ; Case ( JSONGetElement ( $result ; "status" ) = "fail" ; "pass" ; "error" )  ; JSONString ] ;
	[ "result"   ; $result                                                                        ; JSONObject ] ;
	[ "note"     ; "Expected: fail — Status is already Knjižena."                               ; JSONString ]
)

Value.Calculation:
JSONSetElement ( "{}" ;
	[ "kalkulacijaID"  ; KMP__KalkulacijaMP::PrimaryKey    ; JSONString ] ;
	[ "status"         ; KMP__KalkulacijaMP::Status        ; JSONString ] ;
	[ "ukupnoMP_Roba"  ; KMP__KalkulacijaMP::UkupnoMP_Roba ; JSONNumber ] ;
	[ "stavkeCount"    ; $stavkeCount                       ; JSONNumber ]
)

Step.Calculation:
JSONSetElement ( "{}" ;
	[ "test"     ; "Verify final state"                                                                                                                                  ; JSONString ] ;
	[ "severity" ; Case ( KMP__KalkulacijaMP::Status = "Knjižena" and KMP__KalkulacijaMP::UkupnoMP_Roba > 0 ; "pass" ; "error" )                                        ; JSONString ] ;
	[ "result"   ; $verify                                                                                                                                               ; JSONObject ]
)

JSONSetElement ( "{}" ;
	[ "test"     ; "Verify final state"                                                           ; JSONString ] ;
	[ "severity" ; "error"                                                                         ; JSONString ] ;
	[ "result"   ; JSONSetElement ( "{}" ; "error" ; "Record not found for PK: " & $kalkulacijaID ; JSONString ) ; JSONObject ]
)

JSONSetElement ( "{}" ;
	[ "test"     ; "RefreshTotals (regression)"                                                                     ; JSONString ] ;
	[ "severity" ; Case ( Get ( FoundCount ) = 1 and KMP__KalkulacijaMP::UkupnoMP_Roba > 0 ; "pass" ; "error" )   ; JSONString ] ;
	[ "result"   ; JSONSetElement ( "{}" ; "ukupnoMP_Roba" ; KMP__KalkulacijaMP::UkupnoMP_Roba ; JSONNumber )       ; JSONObject ] ;
	[ "note"     ; "UkupnoMP_Roba must remain > 0 after RefreshTotals runs on a Knjižena record."                   ; JSONString ]
)

JSONSetElement ( "{}" ;
	[ "label" ; "Test__KMP_Flow" ; JSONString ] ;
	[ "vars"  ; JSONSetElement ( "{}" ;
		[ "kalkulacijaID" ; $kalkulacijaID ; JSONString ] ;
		[ "stavkeCount"   ; $stavkeCount   ; JSONNumber ] ;
		[ "log"           ; $$log          ; JSONRaw    ]
	) ; JSONRaw ]
)
